15	// Additive.glsl
16	precision mediump float;
17	
18	uniform sampler2D u_MainTex;
19	
20	varying vec4 v_color;
21	varying vec2 v_texcoord0;
22	
23	vec4 bloomColor(vec4 color, float gain) {
24	  // Guarantee that there's at least a little bit of all 3 channels.
25	  // This makes fully-saturated strokes (which only have 2 non-zero
26	  // color channels) eventually clip to white rather than to a secondary.
27	  float cmin = length(color.rgb) * .05;
28	  color.rgb = max(color.rgb, vec3(cmin, cmin, cmin));
29	  // If we try to remove this pow() from .a, it brightens up
30	  // pressure-sensitive strokes; looks better as-is.
31	  color.r = pow(color.r, 2.2);
32	  color.g = pow(color.g, 2.2);
33	  color.b = pow(color.b, 2.2);
34	  color.a = pow(color.a, 2.2);
35	  color.rgb *= 2.0 * exp(gain * 10.0);
36	  return color;
37	}
38	
39	void main() {
40	  const float emission_gain = TB_EMISSION_GAIN;
41	  float brush_mask = texture2D(u_MainTex, v_texcoord0).w;
42	  gl_FragColor = brush_mask * bloomColor(v_color, emission_gain);
43	}
